// ======================================================
// 1. FONTE A — DICIONÁRIO DO BANCO (INPUT DO NODE)
// ======================================================
const referenceData = $input.all().map(i => i.json);

// ======================================================
// 2. FONTE B — DADOS DO USUÁRIO (TRIGGER / WEBHOOK)
// ======================================================
let userData = null;

const possibleTriggerNodes = [
  'When Executed by Another Workflow',
  'Edit Fields',
  'Trigger',
  'Webhook',
  'Start'
];

for (const nodeName of possibleTriggerNodes) {
  try {
    const item = $(nodeName).first();
    if (item?.json?.Fields && item?.json?.Values) {
      userData = item.json;
      break;
    }
  } catch {}
}

if (!userData) {
  throw new Error("Não foi possível localizar Fields/Values no Trigger.");
}

// ======================================================
// 3. FUNÇÕES UTILITÁRIAS
// ======================================================
function normalize(str = "") {
  return str
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]/g, "");
}

// A função classifyField agora é apenas um auxiliar, não define o fluxo principal
function classifyField(fieldName) {
  const n = normalize(fieldName);
  if (n.includes("endereco")) return "ADDRESS_FULL";
  if (n.includes("aeroporto")) return "AIRPORT";
  return "OTHER";
}

function buildResult(ref, originalInput, value, participantId, eventId) {
  return {
    participant_id: participantId,
    event_id: eventId,
    field_name: ref.field_name,
    field_id: ref.field_id,
    field_type: ref.field_type,
    description: ref.description || null,
    format_example: ref.format_example || null,
    options: ref.options || [],
    value,
    _original_input: originalInput
  };
}


// ======================================================
// 4. PROCESSAMENTO
// ======================================================
const fieldsList = userData.Fields;
const valuesList = userData.Values;
const participantId = userData.participant_id;
const eventId = userData.event_id;

const matchedFields = [];

for (let i = 0; i < fieldsList.length; i++) {
  const inputFieldName = fieldsList[i];
  const inputValue = valuesList[i] ?? null;
  const normalizedInput = normalize(inputFieldName);

  let matchFound = false;

  // ---------------------------
  // 1. TENTATIVA DE MATCH DIRETO (PRIORIDADE ABSOLUTA)
  // ---------------------------

  // A. Tenta Exato
  let match = referenceData.find(ref => {
    if (!ref.field_name) return false;
    return normalize(ref.field_name) === normalizedInput;
  });

  // B. Tenta "Banco contém Input"
  if (!match) {
    match = referenceData.find(ref => {
      if (!ref.field_name) return false;
      const refNorm = normalize(ref.field_name);
      return refNorm.includes(normalizedInput);
    });
  }

  // C. Match semântico leve (remove "de", "do", "da")
  if (!match) {
      match = referenceData.find(ref => {
        if (!ref.field_name) return false;

        const refNorm = normalize(ref.field_name)
          .replace(/(de|do|da|das|dos)/g, "");

        const inputNorm = normalizedInput
          .replace(/(de|do|da|das|dos)/g, "");

        return refNorm === inputNorm;
      });
  }


  // Se achou match direto, salva e PULA para o próximo campo (continue)
  if (match) {
    matchedFields.push(
      buildResult(match, inputFieldName, inputValue, participantId, eventId)
    );
    matchFound = true;
    continue; // <--- ISSO EVITA A DUPLICAÇÃO
  }

  // ---------------------------
  // 2. HEURÍSTICAS (SÓ RODA SE NÃO DEU MATCH DIRETO)
  // ---------------------------
  if (!matchFound) {
    const fieldType = classifyField(inputFieldName);

    // --- ENDEREÇO COMPLETO ---
    // (Só entra aqui se o input for algo genérico como "Endereço Completo"
    // e não tiver batido com nenhum campo específico antes)
    if (fieldType === "ADDRESS_FULL") {
      const addressFields = [
        "enderecoruaenumero",
        "complemento",
        "bairro",
        "cidade",
        "estado",
        "cep"
      ];

      referenceData.forEach(ref => {
        if (addressFields.includes(normalize(ref.field_name))) {
          matchedFields.push(
            buildResult(ref, inputFieldName, inputValue, participantId, eventId)
          );
        }
      });
    }

    // --- AEROPORTOS ---
    if (fieldType === "AIRPORT") {
      referenceData.forEach(ref => {
        const n = normalize(ref.field_name);
        if (n === "aeroportoida" || n === "aeroportovolta") {
          matchedFields.push(
            buildResult(ref, inputFieldName, inputValue, participantId, eventId)
          );
        }
      });
    }
  }
}

// ======================================================
// 5. GERAR PROMPT PARA O AI AGENT
// ======================================================
const userMessage = `Formate os valores dos campos abaixo seguindo EXATAMENTE o padrão definido em format_example.

## CAMPOS PARA FORMATAR

${JSON.stringify(matchedFields, null, 2)}

## INSTRUÇÕES
- Analise cada campo e seu format_example
- Formate o value para seguir o mesmo padrão do format_example
- Retorne um JSON com formatted_fields contendo:
  - field_id
  - original_value
  - formatted_value
  - changed (boolean)`;

// ======================================================
// 6. RETORNO FINAL
// ======================================================
return {
  json: {
    participant_id: participantId,
    event_id: eventId,
    fields: matchedFields,
    user_message: userMessage
  }
};

// ===============================
// ENTRADA
// ===============================

// 1️⃣ Estado atual dos campos (vem do node Documentos que faltam)
const fields = items.map(i => i.json);

// 2️⃣ Campos atualizados NESTA execução
const camposAtualizadosAgora = $items('Processar Resposta do AI Agent')
  .map(i => i.json)
  .filter(f => f._collected_now === true)
  .map(f => f._field_name);

// ===============================
// HELPERS
// ===============================
const getField = (name) =>
  fields.find(f => f.field_name === name);

const isColetado = (name) =>
  getField(name)?.status === 'COLETADO';

const listarCampos = (campos) =>
  campos.map(c => `• ${c.field_name}`).join('\n');

// ===============================
// PENDÊNCIAS
// ===============================
const obrigatoriosPendentes = fields.filter(
  f => f.is_required === true && f.status === 'PENDENTE'
);

const opcionaisPendentes = fields.filter(
  f => f.is_required === false && f.status === 'PENDENTE'
);

// ===============================
// REGRA DE LOGÍSTICA
// ===============================

// 1. Verifica status do Transporte
const transporteField = getField('Tipo de Transporte');
const transporteColetado = isColetado('Tipo de Transporte');
const valorTransporte = transporteField?.value;
const transportePendente = !transporteColetado;

// 2. Regra de Exclusão (NOVA LÓGICA) 🛑
// Se for Carro ou Outro, NÃO precisa de sugestão logística
const transporteRequerLogistica = ![
  'Carro próprio',
  'Outro (carona, aplicativo, táxi, etc.)',
  'Outro' // Segurança caso venha simplificado
].includes(valorTransporte);

// 3. Endereço completo
const enderecoMinimoColetado =
  isColetado('Endereço (rua e número)') &&
  isColetado('Cidade') &&
  isColetado('Estado');

// 4. O que mudou AGORA
const atualizouTransporteAgora =
  camposAtualizadosAgora.includes('Tipo de Transporte');

const atualizouEnderecoAgora =
  camposAtualizadosAgora.some(c =>
    [
      'Endereço (rua e número)',
      'Bairro',
      'Cidade',
      'Estado',
      'CEP'
    ].includes(c)
  );

// ===============================
// CONDIÇÃO FINAL DE DISPARO
// ===============================
const deveSugerirLogistica =
  transportePendente &&
  enderecoMinimoColetado;

// ===============================
// MENSAGEM PADRÃO
// ===============================
let mensagem = '';

// CENÁRIO 1 — Ainda faltam obrigatórios
if (obrigatoriosPendentes.length > 0) {
  mensagem =
`✅ Dados cadastrados com sucesso!

Mas ainda faltam alguns dados *obrigatórios* para finalizar sua inscrição:

${listarCampos(obrigatoriosPendentes)}

Assim que puder, é só me enviar essas informações por aqui 😊`;
}

// CENÁRIO 2 — Só opcionais pendentes
else if (opcionaisPendentes.length > 0) {
  mensagem =
`✅ Dados cadastrados com sucesso!

Seu status pode ser atualizado para *Confirmado* 🎉  
Mas ainda faltam alguns dados *opcionais* que ajudam a melhorar sua experiência no evento:

${listarCampos(opcionaisPendentes)}

Se quiser completar depois, é só me avisar 😉`;
}

// CENÁRIO 3 — Tudo coletado
else {
  mensagem =
`🎉 Dados cadastrados com sucesso!

Todos os dados necessários já foram coletados.  
Obrigada! Qualquer coisa, é só chamar 😊`;
}

// ===============================
// RETORNO FINAL
// ===============================
return [
  {
    json: {
      mensagem,
      resumo: {
        obrigatorios_pendentes: obrigatoriosPendentes.length,
        opcionais_pendentes: opcionaisPendentes.length,
        total_campos: fields.length
      },
      logistica: {
        acionar_sugestao: deveSugerirLogistica,
        tipo_transporte: valorTransporte || null,
        endereco_minimo: enderecoMinimoColetado
      }
    }
  }
];

// Pega a resposta do AI Agent
const aiOutput = $input.first().json;

// Pega os dados originais (participant_id, event_id) do nó anterior ao AI Agent
// Ajuste o nome do nó conforme seu fluxo
let originalData = null;
const possibleNodes = ['Code', 'Code1', 'Montar contexto', 'Prepara os dados'];

for (const nodeName of possibleNodes) {
  try {
    const item = $(nodeName).first();
    if (item && item.json && item.json.participant_id) {
      originalData = item.json;
      break;
    }
  } catch (e) {
    // Nó não existe, continua
  }
}

// Se não encontrou, tenta pegar do trigger
if (!originalData) {
  const triggerNodes = ['When Executed by Another Workflow', 'Webhook', 'Trigger'];
  for (const nodeName of triggerNodes) {
    try {
      const item = $(nodeName).first();
      if (item && item.json && item.json.participant_id) {
        originalData = item.json;
        break;
      }
    } catch (e) {
      // Continua
    }
  }
}

// Parse da resposta do AI (vem como string JSON)
let formattedFields = [];
try {
  const parsed = typeof aiOutput.output === 'string' 
    ? JSON.parse(aiOutput.output) 
    : aiOutput.output;

  formattedFields = parsed.formatted_fields || [];
} catch (e) {
  // Tenta extrair JSON do texto se veio com texto extra
  const match = aiOutput.output.match(/\{[\s\S]*\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    formattedFields = parsed.formatted_fields || [];
  }
}

// Monta os itens para o Loop
const items = formattedFields.map(field => ({
  json: {
    // IDs para o upsert
    participant_id: originalData?.participant_id || null,
    field_id: field.field_id,

    // Valor formatado para salvar
    value: field.formatted_value,

    // Timestamp de preenchimento
    filled_at: new Date().toISOString(),

    // Metadados (opcional, para debug/log)
    _field_name: field.field_name,
    _original_value: field.original_value,
    _was_changed: field.changed,
    _collected_now: true                  // coleta
  }
}));

return items;

// Prepara os dados finais para o Supabase (SEM normalização)
const results = [];

// Dados vindos do loop principal
const loopData = $('Loop Over Items').first().json;

for (const item of $input.all()) {
  const data = item.json;

  const participantId = loopData.participant_id;
  const fieldId = data.field_id;      // UUID do campo (null para base)
  const value = data.value ?? null;   // Valor já tratado anteriormente

  // Apenas campos customizados vão para a tabela de respostas
  if (participantId && fieldId) {
    results.push({
      json: {
        participant_id: participantId,
        field_id: fieldId,
        value: value,
        filled_at: new Date().toISOString(),
        updated_at: new Date().toISOString()
      }
    });
  }
}

return results;
